export const fetchMyJobs = async (params: any) => {
  try {
    const response = await client.get(getMyJobs, {
      params,
    });
    return {
      status: response.status,
      code: response.status,
      data: response.data?.data,
    };
  } catch (error: any) {
    logger('error fetchMyJobs', error);
    return {
      message: error?.response?.data?.message,
      code: error?.code,
      status: error?.status,
    };
  }
};

