import {
  GET_FRIEND_REFERRAL_ASYNC,
  GET_FRIEND_REFERRAL_FAILED,
  GET_FRIEND_REFERRAL_PROGRESS,
  GET_FRIEND_REFERRAL_SUCCESS,
  GET_FRIEND_REFERRAL_DETAIL_ASYNC,
  GET_FRIEND_REFERRAL_DETAIL_FAILED,
  GET_FRIEND_REFERRAL_DETAIL_PROGRESS,
  GET_FRIEND_REFERRAL_DETAIL_SUCCESS,
  GET_FRIEND_REFERRAL_DETAIL_CLEAR,
} from './contants';

// action saga
export const getFriendReferralAsync = () =>
  ({ type: GET_FRIEND_REFERRAL_ASYNC } as const);

// action reducer
export const getFriendReferralSuccess = (payload: any) =>
  ({ type: GET_FRIEND_REFERRAL_SUCCESS, payload } as const);
export const getFriendReferralFailed = (payload: any) =>
  ({ type: GET_FRIEND_REFERRAL_FAILED, payload } as const);
export const getFriendReferralProgress = (payload: boolean) =>
  ({ type: GET_FRIEND_REFERRAL_PROGRESS, payload } as const);

export const getFriendReferralDetailAsync = (payload: string) =>
  ({ type: GET_FRIEND_REFERRAL_DETAIL_ASYNC, payload } as const);
export const getFriendReferralDetailSuccess = (payload: any) =>
  ({ type: GET_FRIEND_REFERRAL_DETAIL_SUCCESS, payload } as const);
export const getFriendReferralDetailFailed = (payload: any) =>
  ({ type: GET_FRIEND_REFERRAL_DETAIL_FAILED, payload } as const);
export const getFriendReferralDetailProgress = (payload: boolean) =>
  ({ type: GET_FRIEND_REFERRAL_DETAIL_PROGRESS, payload } as const);
export const getFriendReferralDetailClear = () =>
  ({ type: GET_FRIEND_REFERRAL_DETAIL_CLEAR } as const);

export const actionReferFriend = {
  getFriendReferralAsync,
  getFriendReferralSuccess,
  getFriendReferralFailed,
  getFriendReferralProgress,
  getFriendReferralDetailAsync,
  getFriendReferralDetailSuccess,
  getFriendReferralDetailFailed,
  getFriendReferralDetailProgress,
  getFriendReferralDetailClear,
};

export type ReferFriendAction = ReturnType<
  | typeof getFriendReferralAsync
  | typeof getFriendReferralSuccess
  | typeof getFriendReferralFailed
  | typeof getFriendReferralProgress
  | typeof getFriendReferralDetailAsync
  | typeof getFriendReferralDetailSuccess
  | typeof getFriendReferralDetailFailed
  | typeof getFriendReferralDetailProgress
  | typeof getFriendReferralDetailClear
>;
