const submitComment = function* (action: {
  type: string;
  payload: CommentPayload;
}): Generator<any, void, any> {
  const {
    fileDatas: inputFiles,
    onSuccess,
    onError,
    ...commentPayload
  } = action.payload;

  try {
    yield put({ type: GET_COMMENT_CHECKLIST_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });

    let uploadedFileDatas: FileData[] = [];

    // Process files - upload local files to S3, keep already uploaded files
    // If notS3 is true, skip S3 upload and pass files directly
    if (inputFiles && inputFiles.length > 0) {
      if (commentPayload.notS3) {
        // notS3 mode: Pass files directly without S3 upload (for JobReady)
        uploadedFileDatas = inputFiles.map((file: FileData) => ({
          ...file,
          // Keep original file data for direct API upload
        }));
      } else {
        // Default mode: Upload to S3 first
        for (const file of inputFiles) {
          try {
            // Check if file is already uploaded (has url but no uri/path)
            const isLocalFile = !!(file.uri || file.path);
            const isAlreadyUploaded = !!file.url && !isLocalFile;

            if (isAlreadyUploaded) {
              // File already uploaded, keep as is
              uploadedFileDatas.push(file);
              continue;
            }

            if (!isLocalFile) {
              logger('File has no uri/path to upload:', file.fileName);
              continue;
            }

            // Local file - need to upload to S3
            const mime = file.mime || 'image/jpeg';
            const defaultInfo = getDefaultFileInfo(mime);
            const fileName = file.fileName || defaultInfo.name;
            const isVideo = isVideoFile(mime);

            // Step 1: Compress image or video
            let compressedFile: {
              uri: string;
              size: number | undefined;
            } | null = null;

            if (isVideo) {
              compressedFile = yield call(
                compressVideo,
                file.path || file.uri || '',
              );
            } else {
              compressedFile = yield call(
                compressImage,
                file.path || file.uri || '',
              );
            }

            if (!compressedFile) {
              logger('Failed to compress file:', fileName);
              continue;
            }

            // Step 2: Get presigned URL from S3
            const uploadFileData = {
              folder: 'checklist',
              fileName: fileName,
              contentType: mime,
            };

            const presignedResponse: any = yield call(
              fetchPresignedUrlS3,
              uploadFileData,
            );

            // Check response structure
            if (!presignedResponse?.data) {
              logger('Failed to get presigned URL for:', fileName);
              continue;
            }

            const {
              url: presignedUrl,
              key,
              fileId,
              s3BaseUrl,
            } = presignedResponse.data;

            if (!presignedUrl || typeof presignedUrl !== 'string') {
              logger('Invalid presigned URL for:', fileName);
              continue;
            }

            // Step 3: Upload compressed file to S3 using presigned URL
            try {
              const fetchResponse: Response = yield call(
                fetch,
                compressedFile.uri,
              );
              const fileBlob: Blob = yield call([fetchResponse, 'blob']);

              yield call(axios.put, presignedUrl, fileBlob, {
                headers: {
                  'Content-Type': mime,
                },
                transformRequest: (data: any, headers: any) => {
                  delete headers.Accept;
                  delete headers['Content-Length'];
                  return data;
                },
              });
            } catch (putError) {
              logger('Failed to upload to S3:', putError);
              continue;
            }

            // Step 4: Add to uploadedFileDatas array with correct format
            const fileExtension = '.' + fileName.split('.').pop();

            // Construct the final S3 URL (without query params)
            const uploadFileUrl = s3BaseUrl
              ? `${s3BaseUrl}/${key}`
              : presignedUrl.split('?')[0];

            uploadedFileDatas.push({
              fileId: fileId,
              fileName: fileName,
              fileLength: compressedFile.size || 0,
              fileExtension: fileExtension,
              key: key,
              url: uploadFileUrl,
            });

            yield delay(300);
          } catch (uploadError) {
            logger('Error processing/uploading file:', uploadError);
          }
        }
      }
    }

    // Step 5: Build final payload and call API
    const finalPayload: CommentPayload = {
      ...commentPayload,
      fileDatas: uploadedFileDatas.length > 0 ? uploadedFileDatas : [],
    };

    // Check if this request has comment or files (not just isChecked update)
    const hasCommentOrFile =
      !!(commentPayload.comment && commentPayload.comment.trim().length > 0) ||
      uploadedFileDatas.length > 0;

    // Call different API based on notS3 flag (notS3=true means JobReady mode)
    const response = commentPayload.notS3 ?? false
      ? ((yield call(fetchCommentProjectReady, finalPayload)) as ResponseApi)
      : ((yield call(fetchComment, finalPayload)) as ResponseApi);

    if (response.status !== 200) {
      yield put({
        type: GET_COMMENT_CHECKLIST_FAILED,
        payload: response.message,
        screenKey: commentPayload.screenKey,
      });

      // Only show error toast if there was comment or file

      yield call(Toast.show, {
        text1: response.message || i18n.t('SUBMIT_COMMENT_FAILED'),
        type: 'error',
      });

      if (onError) {
        onError(response.message);
      }
      return;
    }

    // Merge selectedOption from request if not in response (for JobReady)
    const successPayload = {
      ...response.data,
      // Include selectedOption from request if it was provided
      ...(commentPayload.selectedOption !== undefined && {
        selectedOption: commentPayload.selectedOption,
      }),
    };

    yield put({
      type: GET_COMMENT_CHECKLIST_SUCCESS,
      payload: successPayload,
      screenKey: commentPayload.screenKey,
    });

    // Only show success toast if there was comment or file
    if (hasCommentOrFile) {
      yield call(Toast.show, {
        text1: i18n.t('SUBMIT_COMMENT_SUCCESS'),
        type: 'success',
      });
    }

    if (onSuccess) {
      onSuccess();
    }
  } catch (error: any) {
    logger('Error in submitComment:', error);
    yield put({ type: GET_COMMENT_CHECKLIST_FAILED, payload: error });

    // Only show error toast if there was comment or file in the original request
    const hasCommentOrFile =
      !!(action.payload.comment && action.payload.comment.trim().length > 0) ||
      !!(action.payload.fileDatas && action.payload.fileDatas.length > 0);

    if (hasCommentOrFile) {
      yield call(Toast.show, {
        text1: i18n.t('SUBMIT_COMMENT_FAILED'),
        type: 'error',
      });
    }

    if (onError) {
      onError(error);
    }
  } finally {
    yield put({ type: GET_COMMENT_CHECKLIST_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

const saveWorkOrderChecklist = function* (action: {
  type: string;
  payload: SaveWorkOrderChecklistPayload;
}): Generator<any, void, any> {
  const { onSuccess, onError, ...payload } = action.payload;

  try {
    yield put({ type: SAVE_WORK_ORDER_CHECKLIST_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });

    const response = (yield call(
      fetchSaveWorkOrderChecklist,
      payload,
    )) as ResponseApi;

    if (response.status !== 200) {
      yield put({
        type: SAVE_WORK_ORDER_CHECKLIST_FAILED,
        payload: response.message,
      });

      yield call(Toast.show, {
        text1: response.message || payload.isCompleted ? i18n.t('COMPLETE_CHECKLIST_FAILED') : i18n.t('SAVE_CHECKLIST_FAILED'),
        type: 'error',
      });

      if (onError) {
        onError(response.message);
      }
      return;
    }

    yield put({
      type: SAVE_WORK_ORDER_CHECKLIST_SUCCESS,
      payload: response.data,
    });

    yield call(Toast.show, {
      text1: payload.isCompleted
        ? i18n.t('COMPLETE_CHECKLIST_SUCCESS')
        : i18n.t('SAVE_CHECKLIST_SUCCESS'),
      type: 'success',
    });

    if (onSuccess) {
      onSuccess();
    }
  } catch (error: any) {
    logger('Error in saveWorkOrderChecklist:', error);
    yield put({ type: SAVE_WORK_ORDER_CHECKLIST_FAILED, payload: error });

    yield call(Toast.show, {
      text1: i18n.t('SAVE_WORK_ORDER_FAILED'),
      type: 'error',
    });

    if (onError) {
      onError(error);
    }
  } finally {
    yield put({ type: SAVE_WORK_ORDER_CHECKLIST_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

