export default function* jobDetailSaga() {
  yield takeEvery(GET_WORK_ORDER_DETAIL_ASYNC, getWorkOrderDetail);
  yield takeEvery(GET_MATERIAL_LIST_ASYNC, getMaterialList);
  yield takeEvery(GET_CHAT_GROUP_ASYNC, getChatGroup);
  yield takeEvery(GET_COMMENT_CHECKLIST_ASYNC, submitComment);
  yield takeEvery(SAVE_WORK_ORDER_CHECKLIST_ASYNC, saveWorkOrderChecklist);
  // JobReady checklist sagas
  yield takeEvery(GET_JOB_READY_DATA_ASYNC, getJobReadyData);
  yield takeEvery(SUBMIT_JOB_READY_FORM_ASYNC, submitJobReadyForm);
  yield takeEvery(SAVE_JOB_READY_ITEM_ASYNC, saveJobReadyItem);
}
